</section>
<script>
	document.addEventListener(\'click\', function(e) {
		if (e.target.closest(\'.js-add-to-cart\')) {
			const btn = e.target.closest(\'.js-add-to-cart\');
			const card = e.target.closest(\'.card\')
			const cardBottom = card.querySelector(\'.catalog__item_bottom\')
			// const counter = card.querySelector(\'[name=quantity]\')
			// const qty = counter.value
			
			if (!btn) {
				return;
			}

			btn.disabled = true

			e.preventDefault();

			BX.ajax({
			url: \'/local/ajax/cart.php\',
				method: \'POST\',
				dataType: \'json\',
				data: {
					action: \'add\',
					id: btn.dataset.id,
					quantity: 1
				},
				onsuccess: function(response) {
					BX.onCustomEvent(\'OnBasketChange\');
					BX.ajax({
						url: location.href,
						method: \'GET\',
						dataType: \'html\',
						processData: false,
						onsuccess: (res) => {

							// const newCardBottom = $(res).find(`#${cardBottom.id}`);

							// if (newCardBottom) {
							// 	$(cardBottom).replaceWith($(newCardBottom));
							// }
							const parser = new DOMParser();
							const doc = parser.parseFromString(res, \'text/html\');

							const newCardBottom = doc.querySelector(`#${cardBottom.id}`);

							if (newCardBottom) {
								cardBottom.replaceWith(newCardBottom);
							}
						}
					})
					
				}
			});
		}

		if (e.target.closest(\'.js-remove-to-cart\')) {
			const btn = e.target.closest(\'.js-remove-to-cart\');
			const card = e.target.closest(\'.card\')
			const counter = card.querySelector(\'[name=quantity]\')
			const qty = counter.value
			const basketId = card.dataset.basketId;
			const cardBottom = card.querySelector(\'.catalog__item_bottom\')
			
			
			if (!btn) {
				return;
			}
			btn.disabled = true

			e.preventDefault();

			BX.ajax({
				url: \'/local/ajax/cart.php\',
				method: \'POST\',
				dataType: \'json\',
				data: {
					action: \'delete\',
					id: btn.dataset.id
				},
				onsuccess: function(response) {
					BX.onCustomEvent(\'OnBasketChange\');
					BX.ajax({
						url: location.href,
						method: \'GET\',
						dataType: \'html\',
						processData: false,
						onsuccess: (res) => {

							// const newCardBottom = $(res).find(`#${cardBottom.id}`);

							// if (newCardBottom) {
							// 	$(cardBottom).replaceWith($(newCardBottom));
							// }
							const parser = new DOMParser();
							const doc = parser.parseFromString(res, \'text/html\');

							const newCardBottom = doc.querySelector(`#${cardBottom.id}`);

							if (newCardBottom) {
								cardBottom.replaceWith(newCardBottom);
							}
						}
					})
				}
			});
		}

		if (e.target.closest(\'.dec\')) {
			const btn = e.target.closest(\'.dec\');
			const card = e.target.closest(\'.card\')
			const cardBottom = card.querySelector(\'.catalog__item_bottom\')
			const counter = card.querySelector(\'[name=quantity]\')
			const qty = counter.value
			
			if (!btn) {
				return;
			}
				btn.disabled = true

			if (qty <= 0) {
				BX.ajax({
				url: \'/local/ajax/cart.php\',
				method: \'POST\',
				dataType: \'json\',
				data: {
					action: \'delete\',
					id: card.dataset.basketId
				},
				onsuccess: function(response) {
					BX.onCustomEvent(\'OnBasketChange\');
					BX.ajax({
						url: location.href,
						method: \'GET\',
						dataType: \'html\',
						processData: false,
						onsuccess: (res) => {
							btn.disabled = false
							// const newCardBottom = $(res).find(`#${cardBottom.id}`);

							// if (newCardBottom) {
							// 	$(cardBottom).replaceWith($(newCardBottom));
							// }
							const parser = new DOMParser();
							const doc = parser.parseFromString(res, \'text/html\');

							const newCardBottom = doc.querySelector(`#${cardBottom.id}`);

							if (newCardBottom) {
								cardBottom.replaceWith(newCardBottom);
							}
						}
					})
				}
			});
			} else {

				BX.ajax({
					url: \'/local/ajax/cart.php\',
					method: \'POST\',
					dataType: \'json\',
					
					data: {
						action: \'update\',
						id: card.dataset.basketId,
						quantity: qty
					},
					onsuccess: function(response) {
						BX.onCustomEvent(\'OnBasketChange\');
						btn.disabled = false
						
					}
				});
			}
			
		}

		if (e.target.closest(\'.inc\')) {
			const btn = e.target.closest(\'.inc\');
			const card = e.target.closest(\'.card\')
			const cardBottom = card.querySelector(\'.catalog__item_bottom\')
			const counter = card.querySelector(\'[name=quantity]\')
			const qty = counter.value
			
			if (!btn) {
				return;
			}

			
			btn.disabled = true

			BX.ajax({
				url: \'/local/ajax/cart.php\',
				method: \'POST\',
				dataType: \'json\',
				data: {
					action: \'update\',
					id: card.dataset.basketId,
					quantity: qty
				},
				onsuccess: function(response) {
					BX.onCustomEvent(\'OnBasketChange\');
					btn.disabled = false
					// BX.ajax({
					// 	url: location.href,
					// 	method: \'GET\',
					// 	dataType: \'html\',
					// 	onsuccess: (res) => {

					// 		const newCardBottom = $(res).find(`#${cardBottom.id}`);

					// 		if (newCardBottom) {
					// 			$(cardBottom).replaceWith($(newCardBottom));
					// 		}
					// 	}
					// })
					
				},
			});
			
			
		}
		
	});
